"""
solution.py

Reads numbers.txt, sums the integers, and prints the total.
"""

def main():
    total = 0
    try:
        with open("numbers.txt", "r") as f:
            for line in f:
                stripped = line.strip()
                if stripped:  # skip empty lines
                    try:
                        num = int(stripped)
                        total += num
                    except ValueError:
                        print(f"Warning: Skipping non-integer line: {stripped}")
    except FileNotFoundError:
        print("Error: numbers.txt not found.")
        return

    print(total)

if __name__ == "__main__":
    main()

